-- Editorial: add 3 timely, sourced Saudi accounting articles (ZATCA fines waiver
-- extension, e-invoicing Wave 23/24, SOCPA 2026-2030 strategy), including X/Twitter
-- references, as requested by the site owner.

INSERT INTO public.kb_articles (
  slug, category_id, title_ar, title_en, excerpt_ar, excerpt_en,
  content_ar, meta_title, meta_description, keywords, reading_minutes,
  faq, "references", external_sources, is_featured, status,
  generation_source, published_at
)
VALUES
(
  'zatca-fines-waiver-extended-december-2026',
  (SELECT id FROM public.kb_categories WHERE slug = 'zakat-tax-ksa'),
  'تمديد مبادرة إعفاء الغرامات الضريبية في السعودية حتى 31 ديسمبر 2026',
  'ZATCA Extends Tax Fines Waiver Initiative in Saudi Arabia Until December 31, 2026',
  $$أعلنت هيئة الزكاة والضريبة والجمارك تمديد مبادرة إلغاء الغرامات والإعفاء من العقوبات المالية عن المكلفين لمدة 6 أشهر إضافية اعتباراً من 1 يوليو 2026 وحتى 31 ديسمبر 2026. إليك التفاصيل الكاملة: الغرامات المشمولة، الحالات المستثناة، وخطوات الاستفادة العملية لمنشأتك.$$,
  $$ZATCA has extended its fines-cancellation and penalty-exemption initiative for taxpayers by six additional months, from July 1 to December 31, 2026. Here is what is covered, what is excluded, and how businesses can benefit.$$,
  $$[
    {"heading":"ما الذي أعلنته هيئة الزكاة والضريبة والجمارك؟","paragraphs":[
      "أصدر وزير المالية قراراً بتمديد مبادرة إلغاء الغرامات والإعفاء من العقوبات المالية عن المكلفين الخاضعين لجميع الأنظمة الضريبية في المملكة لمدة ستة أشهر إضافية، اعتباراً من 1 يوليو 2026 وحتى 31 ديسمبر 2026م، بحسب ما أعلنته هيئة الزكاة والضريبة والجمارك (زاتكا) وتناقلته عدة وسائل إعلام سعودية.",
      "يأتي هذا التمديد استمراراً لسلسلة تمديدات سابقة تعود إلى عام 2020، وهو ما يعكس توجه الهيئة نحو تشجيع المنشآت على تصحيح أوضاعها الضريبية طوعاً قبل اللجوء إلى الإجراءات الجزائية."
    ]},
    {"heading":"الغرامات المشمولة بالإعفاء","paragraphs":[
      "تشمل المبادرة الإعفاء من غرامة التسجيل المتأخر في جميع الأنظمة الضريبية، وغرامة التأخير في سداد الضريبة المستحقة، وغرامة التأخير في تقديم الإقرارات في جميع الأنظمة الضريبية، إضافة إلى غرامة تصحيح الإقرار الضريبي في ضريبة القيمة المضافة.",
      "بذلك تغطي المبادرة أكثر المخالفات الضريبية شيوعاً بين المنشآت الصغيرة والمتوسطة، وتحديداً تلك الناتجة عن تأخر إداري أو سهو وليس تهرباً متعمداً."
    ]},
    {"heading":"الحالات المستثناة من المبادرة","paragraphs":[
      "أوضحت الهيئة أن المبادرة لا تشمل الغرامات المرتبطة بمخالفات التهرب الضريبي، ولا الغرامات المفروضة بموجب المادة 45 من نظام ضريبة القيمة المضافة، ولا الغرامات التي سبق سدادها قبل تاريخ نفاذ هذه المبادرة.",
      "كما تستثني المبادرة الغرامات المرتبطة بأي إقرار يستحق تقديمه للهيئة بعد 30 يونيو 2026، أي أن الالتزام بالمواعيد اعتباراً من هذا التاريخ أصبح شرطاً أساسياً للاستفادة من الإعفاء على ما سبقه من مخالفات."
    ]},
    {"heading":"كيف تستفيد منشأتك من التمديد؟","paragraphs":[
      "دعت زاتكا جميع المكلفين إلى المبادرة بتصحيح أوضاعهم الضريبية خلال الفترة الممتدة حتى 31 ديسمبر 2026، عبر التواصل مع مركز الاتصال الموحد على الرقم 19993 المتاح على مدار الساعة، أو من خلال حساب \"اسأل زكاة وضريبة وجمارك\" على منصة إكس، أو عبر البريد الإلكتروني الرسمي.",
      "من الناحية العملية، يُنصح بمراجعة سجل الإقرارات والمدفوعات السابقة مع المحاسب أو المستشار الضريبي لحصر أي التزامات متأخرة والاستفادة من نافذة الإعفاء قبل انتهائها."
    ]},
    {"heading":"توصيات عملية للمحاسبين والمنشآت","paragraphs":[
      "على المحاسب المسؤول عن الملف الضريبي للمنشأة إعداد جدول زمني للإقرارات المستحقة بعد 30 يونيو 2026، نظراً لأن أي تأخير بعد هذا التاريخ لا يستفيد من الإعفاء.",
      "كذلك يُفضّل توثيق أي تصحيح للإقرارات أو سداد متأخر تم خلال فترة المبادرة، لضمان إمكانية إثبات الاستفادة من الإعفاء لدى أي مراجعة لاحقة من الهيئة."
    ]}
  ]$$::jsonb,
  'تمديد إعفاء الغرامات الضريبية في السعودية حتى ديسمبر 2026 | زاتكا',
  'التفاصيل الكاملة لتمديد هيئة الزكاة والضريبة والجمارك مبادرة إلغاء الغرامات حتى 31 ديسمبر 2026: الغرامات المشمولة، الاستثناءات، وخطوات الاستفادة.',
  ARRAY['زاتكا','إعفاء الغرامات الضريبية','هيئة الزكاة والضريبة والجمارك','ضريبة القيمة المضافة','الامتثال الضريبي','السعودية 2026'],
  6,
  $$[
    {"q":"متى تنتهي مبادرة إعفاء الغرامات الضريبية الحالية؟","a":"تنتهي فترة التمديد الحالية في 31 ديسمبر 2026، بعد أن كانت الهيئة قد مددتها سابقاً حتى 30 يونيو 2026."},
    {"q":"هل تشمل المبادرة غرامات ضريبة القيمة المضافة فقط؟","a":"لا، تشمل المبادرة جميع الأنظمة الضريبية التي تطبقها الهيئة، بما في ذلك ضريبة الدخل والزكاة وضريبة القيمة المضافة، إضافة إلى غرامة تصحيح إقرار ضريبة القيمة المضافة تحديداً."},
    {"q":"هل يمكن استرداد غرامة تم سدادها بالفعل؟","a":"لا، استثنت الهيئة صراحة الغرامات التي سبق سدادها قبل تاريخ نفاذ المبادرة، فلا تشملها أحكام الإعفاء بأثر رجعي."},
    {"q":"ماذا يحدث للإقرارات المستحقة بعد 30 يونيو 2026؟","a":"أي غرامة تنشأ عن إقرار يستحق تقديمه بعد هذا التاريخ لا تدخل ضمن نطاق المبادرة، لذا يجب الالتزام بالمواعيد النظامية اعتباراً من الآن."}
  ]$$::jsonb,
  $$[
    {"label":"زاتكا: قرار تمديد مبادرة إلغاء الغرامات (الجولة السابقة حتى 30 يونيو 2026)","url":"https://zatca.gov.sa/ar/MediaCenter/News/Pages/Fines-Exemption-June-2026.aspx"},
    {"label":"زاتكا: قرار تمديد المبادرة حتى 31 ديسمبر 2025 (سابقة تاريخية)","url":"https://zatca.gov.sa/en/MediaCenter/News/Pages/news_1395.aspx"},
    {"label":"صحيفة عكاظ: تمديد إعفاء المكلفين من الغرامات حتى 31 ديسمبر 2026","url":"https://www.okaz.com.sa/local/saudi-arabia/2254809"},
    {"label":"حساب هيئة الزكاة والضريبة والجمارك على منصة X","url":"https://x.com/Zatca_sa"}
  ]$$::jsonb,
  $$[{"name":"ZATCA","url":"https://zatca.gov.sa/ar/MediaCenter/News/Pages/Fines-Exemption-June-2026.aspx"}]$$::jsonb,
  true,
  'published',
  'editorial',
  now()
),
(
  'zatca-e-invoicing-wave-24-2026',
  (SELECT id FROM public.kb_categories WHERE slug = 'vat'),
  'الموجة 24 من الفوترة الإلكترونية في السعودية: نهاية فترة السماح وبدء الإلزام الكامل',
  'Saudi E-Invoicing Wave 24: The Grace Period Ends as Full Enforcement Begins',
  $$بعد دخول الموجتين 23 و24 من مرحلة الربط والتكامل لنظام الفوترة الإلكترونية حيز التنفيذ، وانتهاء الجولة السابقة من مبادرة إعفاء الغرامات في 30 يونيو 2026، تدخل هيئة الزكاة والضريبة والجمارك مرحلة إنفاذ أكثر صرامة. إليك ما يجب أن تعرفه منشأتك عن الحدود والمواعيد والمتطلبات الفنية.$$,
  $$With Waves 23 and 24 of Saudi Arabia's Phase 2 e-invoicing integration now in effect, ZATCA enforcement is tightening. Here is what businesses need to know about thresholds, deadlines, and technical requirements.$$,
  $$[
    {"heading":"لماذا تُعد هذه المرحلة مفصلية؟","paragraphs":[
      "دخلت منظومة الفوترة الإلكترونية \"فاتورة\" في السعودية مرحلة جديدة من الصرامة مع دخول موجتين إضافيتين من مرحلة الربط والتكامل (المرحلة الثانية) حيز التنفيذ خلال النصف الأول من عام 2026، في وقت تتزامن فيه هذه الموجات مع مواعيد نهائية لمبادرة إعفاء الغرامات الضريبية التي كانت تمنح المنشآت هامشاً للتصحيح دون عقوبات فورية.",
      "بالنسبة للمحاسب أو مدير الشؤون المالية في أي منشأة سعودية، فإن فهم هذه الموجات لم يعد اختيارياً، إذ يترتب على التأخر في الربط مع منصة فاتورة غرامات مباشرة بعد انتهاء المهلة المحددة لكل موجة."
    ]},
    {"heading":"الموجة 23: من هي المنشآت المشمولة؟","paragraphs":[
      "استهدفت الموجة الثالثة والعشرون المنشآت المسجلة في ضريبة القيمة المضافة التي تجاوزت إيراداتها الخاضعة للضريبة 750 ألف ريال سعودي خلال عامي 2022 أو 2023 أو 2024، وألزمتها هيئة الزكاة والضريبة والجمارك باستكمال الربط الكامل مع منصة فاتورة بحلول 31 مارس 2026.",
      "تأتي هذه الموجة ضمن نهج تدريجي تتبعه الهيئة منذ انطلاق مرحلة التكامل، حيث تُخطر المنشآت المستهدفة مسبقاً قبل الموعد النهائي بفترة كافية لإتاحة الوقت اللازم للربط الفني."
    ]},
    {"heading":"الموجة 24: خفض الحد الأدنى للإيرادات إلى 375 ألف ريال","paragraphs":[
      "وسّعت الموجة الرابعة والعشرون نطاق الإلزام لتشمل، للمرة الأولى، المنشآت التي تجاوزت إيراداتها الخاضعة للضريبة 375 ألف ريال سعودي خلال الأعوام 2022 أو 2023 أو 2024، وحددت الهيئة 30 يونيو 2026 موعداً نهائياً لربط هذه الفئة بمنصة فاتورة.",
      "خفض الحد الأدنى إلى النصف تقريباً مقارنة بالموجة السابقة يعني عملياً دخول شريحة أوسع من المنشآت الصغيرة ضمن نطاق الإلزام، وهو ما يستدعي من هذه الفئة التحرك المبكر لاختيار حل تقني معتمد بدل الانتظار حتى اقتراب الموعد النهائي."
    ]},
    {"heading":"المتطلبات الفنية لمرحلة الربط والتكامل","paragraphs":[
      "تشترط مرحلة التكامل (المرحلة الثانية) إصدار الفواتير الإلكترونية بصيغة XML أو PDF/A-3 مع تضمين ملف XML، وربط النظام المحاسبي أو نظام نقاط البيع مباشرة عبر واجهة برمجة تطبيقات (API) مع منصة فاتورة التابعة للهيئة، بحيث تُعتمد الفاتورة الضريبية بختم تشفيري وعلامة زمنية ورمز استجابة سريع (QR) قبل تسليمها للعميل.",
      "على عكس المرحلة الأولى التي اكتفت بإصدار فواتير إلكترونية من نظام داخلي، تتطلب هذه المرحلة تكاملاً حياً أو شبه حي مع أنظمة الهيئة حسب نوع الفاتورة، ما يستلزم غالباً الاستعانة بمزود حلول معتمد من زاتكا."
    ]},
    {"heading":"خطوات عملية للامتثال قبل الموعد النهائي","paragraphs":[
      "يُنصح كل منشأة بمراجعة إيراداتها الخاضعة للضريبة لأعوام 2022-2024 لتحديد ما إذا كانت مشمولة بالموجة 23 أو 24، والتواصل مع مزود نظام محاسبي أو ERP معتمد من الهيئة لبدء إجراءات الربط قبل الموعد النهائي بوقت كافٍ.",
      "كما يُفضّل ربط هذا الاستحقاق الفني بمواعيد مبادرة إعفاء الغرامات، والتأكد من أن أي إقرار أو فاتورة مستحقة تصدر وفق المتطلبات الجديدة بالكامل، تجنباً للجمع بين مخالفة الربط ومخالفة التأخير في آن واحد."
    ]}
  ]$$::jsonb,
  'الموجة 24 للفوترة الإلكترونية في السعودية 2026 | زاتكا',
  'أهم ما يجب معرفته عن الموجة 23 والموجة 24 من مرحلة التكامل لنظام فاتورة: الحدود، المواعيد، والمتطلبات الفنية للمنشآت السعودية.',
  ARRAY['الفوترة الإلكترونية','فاتورة','زاتكا','الموجة 24','ضريبة القيمة المضافة','مرحلة التكامل'],
  7,
  $$[
    {"q":"ما الفرق بين الموجة 23 والموجة 24؟","a":"الفارق الرئيسي هو الحد الأدنى للإيرادات الخاضعة للضريبة: 750 ألف ريال للموجة 23 بموعد نهائي 31 مارس 2026، مقابل 375 ألف ريال للموجة 24 بموعد نهائي 30 يونيو 2026."},
    {"q":"هل تشمل الموجة 24 جميع المنشآت الصغيرة؟","a":"تشمل المنشآت التي تجاوزت إيراداتها الخاضعة للضريبة 375 ألف ريال في أحد الأعوام 2022 أو 2023 أو 2024 تحديداً، وليس بالضرورة كل المنشآت الصغيرة، إذ ما تزال هناك منشآت أصغر لم تُدرَج بعد ضمن أي موجة معلنة."},
    {"q":"ماذا يحدث إذا لم تلتزم المنشأة بموعد الربط؟","a":"يترتب على عدم الربط في الموعد المحدد غرامات مخالفة أحكام الفوترة الإلكترونية، وقد تتصاعد هذه الغرامات مع تكرار المخالفة أو استمرارها."},
    {"q":"هل تحتاج كل منشأة مزوداً تقنياً خارجياً للربط؟","a":"ليس بالضرورة إذا كان نظامها المحاسبي أو نظام نقاط البيع الحالي يدعم التكامل مباشرة مع منصة فاتورة، لكن غالبية المنشآت تستعين بمزود حلول معتمد لتبسيط عملية الربط الفني."}
  ]$$::jsonb,
  $$[
    {"label":"زاتكا: مراحل الطرح التدريجي لنظام الفوترة الإلكترونية (الموقع الرسمي)","url":"https://zatca.gov.sa/en/E-Invoicing/Introduction/Pages/Roll-out-phases.aspx"},
    {"label":"زاتكا: معايير اختيار المكلفين المستهدفين في الموجة 24 لمرحلة التكامل","url":"https://zatca.gov.sa/en/Pages/news_1426.aspx"},
    {"label":"EY: Saudi Arabia announces 23rd wave of Phase 2 e-invoicing integration","url":"https://www.ey.com/en_gl/technical/tax-alerts/saudi-arabia-announces-23rd-wave-of-phase-2-e-invoicing-integration"},
    {"label":"VATupdate: Saudi Arabia E-Invoicing 2026 Key Updates and Compliance Rules","url":"https://www.vatupdate.com/2026/06/29/saudi-arabia-e-invoicing-2026-key-updates-and-compliance-rules/"}
  ]$$::jsonb,
  $$[{"name":"ZATCA","url":"https://zatca.gov.sa/en/E-Invoicing/Introduction/Pages/Roll-out-phases.aspx"}]$$::jsonb,
  false,
  'published',
  'editorial',
  now() - interval '1 day'
),
(
  'socpa-strategy-2026-2030',
  (SELECT id FROM public.kb_categories WHERE slug = 'audit'),
  'استراتيجية "سوكبا 2026-2030": ملامح تطور مهنة المحاسبة والمراجعة في السعودية',
  'SOCPA''s 2026-2030 Strategy: Shaping the Future of Accounting and Auditing in Saudi Arabia',
  $$أطلقت الهيئة السعودية للمراجعين والمحاسبين (سوكبا) استراتيجيتها للفترة 2026-2030 بهدف قيادة تحوّل مهني شامل يعزز جاذبية المهنة ويدعم رؤية 2030. نستعرض أبرز محاور الاستراتيجية وآخر مستجدات الهيئة على منصة إكس.$$,
  $$SOCPA has launched its 2026-2030 strategy to lead a comprehensive professional transformation supporting Saudi Vision 2030. Here are the strategy's key pillars and the latest updates from SOCPA's official channels.$$,
  $$[
    {"heading":"لماذا أطلقت سوكبا استراتيجية جديدة؟","paragraphs":[
      "اعتمدت الهيئة السعودية للمراجعين والمحاسبين (سوكبا) استراتيجية جديدة للفترة 2026-2030 تهدف إلى قيادة تحوّل مهني شامل يسهم في رفع جاذبية مهنة المحاسبة والمراجعة، وتعزيز التميز المهني، وتحقيق الريادة العالمية للقطاع المحاسبي السعودي، بما يدعم مستهدفات رؤية المملكة 2030، بحسب ما أعلنته وكالة الأنباء السعودية (واس).",
      "يأتي إطلاق الاستراتيجية في ظل تسارع التحول الرقمي في المنظومة الضريبية والمحاسبية السعودية، بدءاً من الفوترة الإلكترونية وصولاً إلى تطبيقات الذكاء الاصطناعي في المراجعة، ما يفرض على الهيئة تحديث أدوات تأهيل المهنيين ومواكبة المعايير الدولية."
    ]},
    {"heading":"أبرز محاور استراتيجية سوكبا 2026-2030","paragraphs":[
      "تتمحور الاستراتيجية حول رفع كفاءة وجودة مهنة المراجعة والمحاسبة عبر تطوير الأطر التنظيمية والمعايير المهنية، وتوسيع برامج التأهيل والتطوير المهني المستمر للمحاسبين والمراجعين، وتعزيز حضور المهنة السعودية على المستوى الدولي.",
      "كما حصلت الهيئة على شهادة \"هيّاك\" السعودية للجودة من الهيئة السعودية للمواصفات والمقاييس والجودة تقديراً لتميزها في خدمة المستفيدين وتطبيق معايير الجودة في مركز خدمة العملاء بالرياض، وهو مؤشر على التوجه نحو رفع كفاءة الخدمات المقدمة للمهنيين والمنشآت على حد سواء."
    ]},
    {"heading":"سوكبا في الأرقام: مئات الإصلاحات خلال أسابيع قليلة","paragraphs":[
      "في نشرة دورية نشرتها الهيئة عبر حسابها الرسمي على منصة إكس، أشارت سوكبا إلى تنفيذ أكثر من 300 إصلاح وتحديث خلال الفترة من 1 مارس إلى 21 أبريل 2026 وحدها، وهو ما يعكس وتيرة العمل المتسارعة على الأنظمة الداخلية والخدمات المقدمة للمهنيين في إطار الاستراتيجية الجديدة.",
      "يمكن لمتابعي الشأن المحاسبي في السعودية متابعة هذه التحديثات أولاً بأول عبر حساب الهيئة الرسمي على منصة إكس، والذي بات مصدراً رئيسياً لإعلانات الاختبارات المهنية وبرامج التدريب والقرارات التنظيمية."
    ]},
    {"heading":"التوسع الدولي لزمالة سوكبا","paragraphs":[
      "أتاحت الهيئة الحصول على \"زمالة سوكبا\" للمهنيين حول العالم، في خطوة وصفتها بأنها \"خطوة نحو العالمية\"، تهدف إلى تعزيز الاعتراف الدولي بالشهادة المهنية السعودية وفتح آفاق أوسع للمحاسبين والمراجعين السعوديين للتنافس في بيئات عمل عالمية.",
      "تُعد زمالة سوكبا، بحسب متابعين للشأن المهني على منصة إكس، من أهم الشهادات المهنية محلياً وإحدى الشهادات ذات الحضور المتنامي دولياً، وهي مدعومة من صندوق تنمية الموارد البشرية (هدف)، ما يخفض كلفة الحصول عليها على المهنيين السعوديين."
    ]},
    {"heading":"ماذا يعني ذلك للمحاسبين والمراجعين في المملكة؟","paragraphs":[
      "على المحاسبين والمراجعين المرخصين متابعة دليل البرامج التدريبية الذي أصدرته الهيئة لعام 2026 لتحديد ساعات التطوير المهني المستمر المطلوبة، خاصة مع تزايد الاشتراطات المرتبطة بتجديد التراخيص المهنية.",
      "كما يُنصح بمتابعة القنوات الرسمية للهيئة (الموقع الإلكتروني وحساب إكس) بشكل دوري، نظراً لأن كثيراً من القرارات التنظيمية والتحديثات على المعايير المحاسبية والمراجعة تُعلن أولاً عبر هذه القنوات قبل انعكاسها في اللوائح الرسمية."
    ]}
  ]$$::jsonb,
